+#ifndef RMW_STATS_SHIM__STAT_COLLECTOR_HPP_
+#define RMW_STATS_SHIM__STAT_COLLECTOR_HPP_
+
+#include <atomic>
+#include <chrono>
+#include <optional>
+#include <string>
